function solve(s, order, k) {
    const n = s.length;
    let modified = new Array(n).fill(false);
    let starCount = 0;
    let totalValid = 0;

    for (let t = 0; t < n; t++) {
        const index = order[t];
        if (!modified[index]) {
            modified[index] = true;
            starCount++;
            // The number of new valid substrings introduced by this '*' is:
            // (left + 1) * (right + 1), where left is the number of unmodified chars to the left,
            // and right is the number of unmodified chars to the right.
            let left = 0;
            for (let i = index - 1; i >= 0 && !modified[i]; i--) {
                left++;
            }
            let right = 0;
            for (let i = index + 1; i < n && !modified[i]; i++) {
                right++;
            }
            totalValid += (left + 1) * (right + 1);
            if (totalValid >= k) {
                return t;
            }
        }
    }
    return -1;
}

